const c={async verifyToken(o){const t=await fetch("https://api.github.com/user",{headers:{Authorization:`token ${o}`,Accept:"application/vnd.github.v3+json"}});if(!t.ok)throw new Error("Invalid Token");return t.json()},async getRepos(o){const t=await fetch("https://api.github.com/user/repos?sort=updated&per_page=20",{headers:{Authorization:`token ${o}`,Accept:"application/vnd.github.v3+json"}});if(!t.ok)throw new Error("Failed to fetch repositories");return t.json()},async createFile(o,t,s,n,e,a){const r=await fetch(`https://api.github.com/repos/${t}/${s}/contents/${n}`,{method:"PUT",headers:{Authorization:`token ${o}`,Accept:"application/vnd.github.v3+json","Content-Type":"application/json"},body:JSON.stringify({message:a,content:btoa(e)})});if(!r.ok){const i=await r.json();throw new Error(i.message||"Failed to create file")}return r.json()},calculateSkillDNA(o){const t={};o.forEach(e=>{e.language&&(t[e.language]||(t[e.language]={count:0,stars:0}),t[e.language].count++,t[e.language].stars+=e.stargazers_count)});const s=Object.entries(t).map(([e,a])=>{const r=a.count*10+a.stars*2;return{name:e,rawScore:r}});if(s.length===0)return[];const n=Math.max(...s.map(e=>e.rawScore));return s.map(e=>({name:e.name,level:Math.round(e.rawScore/n*95)})).sort((e,a)=>a.level-e.level).slice(0,5)},async getAssignedIssues(o){const t=await fetch("https://api.github.com/issues?filter=assigned&state=open&sort=updated&per_page=10",{headers:{Authorization:`token ${o}`,Accept:"application/vnd.github.v3+json"}});if(!t.ok)throw new Error("Failed to fetch issues");return t.json()},async getRepoById(o,t){const s=await fetch(`https://api.github.com/repositories/${t}`,{headers:{Authorization:`token ${o}`,Accept:"application/vnd.github.v3+json"}});if(!s.ok)throw new Error("Failed to fetch repository details");return s.json()},async getRepoContents(o,t,s,n=""){const e=await fetch(`https://api.github.com/repos/${t}/${s}/contents/${n}`,{headers:{Authorization:`token ${o}`,Accept:"application/vnd.github.v3+json"}});if(!e.ok)throw new Error("Failed to fetch contents");return e.json()},async getRepoIssues(o,t,s){const n=await fetch(`https://api.github.com/repos/${t}/${s}/issues?state=open&sort=updated`,{headers:{Authorization:`token ${o}`,Accept:"application/vnd.github.v3+json"}});if(!n.ok)throw new Error("Failed to fetch repo issues");return n.json()},async getRepoPRs(o,t,s){const n=await fetch(`https://api.github.com/repos/${t}/${s}/pulls?state=open&sort=updated`,{headers:{Authorization:`token ${o}`,Accept:"application/vnd.github.v3+json"}});if(!n.ok)throw new Error("Failed to fetch pull requests");return n.json()}};export{c as githubService};
